// Tests how timestamp request headers are serialized
TEST(RestJsonRequestTest, RestJsonTimestampFormatHeaders) {
  Fixture fixture = MakeFixture();
  const TimestampFormatHeadersInput input = [] {
  TimestampFormatHeadersInput v{};
  v.memberEpochSeconds = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.memberHttpDate = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.memberDateTime = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.defaultFormat = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetEpochSeconds = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetHttpDate = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetDateTime = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  return v;
}();
  (void)fixture.client.TimestampFormatHeaders(input);
  const smithy::http::HttpRequest& request = fixture.transport->last_request;
  EXPECT_EQ(request.method, "POST");
  EXPECT_EQ(smithy::testing::UriPath(request.target), "/TimestampFormatHeaders");
  EXPECT_EQ(request.headers.Get("X-defaultFormat").value_or("<missing>"), "Mon, 16 Dec 2019 23:48:18 GMT");
  EXPECT_EQ(request.headers.Get("X-memberDateTime").value_or("<missing>"), "2019-12-16T23:48:18Z");
  EXPECT_EQ(request.headers.Get("X-memberEpochSeconds").value_or("<missing>"), "1576540098");
  EXPECT_EQ(request.headers.Get("X-memberHttpDate").value_or("<missing>"), "Mon, 16 Dec 2019 23:48:18 GMT");
  EXPECT_EQ(request.headers.Get("X-targetDateTime").value_or("<missing>"), "2019-12-16T23:48:18Z");
  EXPECT_EQ(request.headers.Get("X-targetEpochSeconds").value_or("<missing>"), "1576540098");
  EXPECT_EQ(request.headers.Get("X-targetHttpDate").value_or("<missing>"), "Mon, 16 Dec 2019 23:48:18 GMT");
  EXPECT_TRUE(request.body.empty()) << request.body;
}

